pub fn compute_margin_requirement_by_mode(
    result: *mut i64,
    pos: *const i64,
    oracle_px_ptr: *const i64,
    margin_mode: i32,
    leverage: i32,
) {
    let oracle_px_int: i64 = unsafe { *oracle_px_ptr.add(3) };
    let raw_notional: i64 = oracle_px_int.wrapping_mul(unsafe { *pos.add(2) });
    let abs_notional: i64 = raw_notional.wrapping_abs();
    let out: *mut i64 = result;
    let _ = (margin_mode, leverage);
    unsafe {
        *out.add(0) = oracle_px_int;
        *out.add(2) = raw_notional;
        *out.add(9) = abs_notional;
    }
}

