fn compute_adl_ranking_score(clearinghouse_ptr: *mut u8, user_address: i64, market_idx: i64, is_long: i8) -> i64 {
    unsafe {
        let rsi = *(clearinghouse_ptr.add(0xe8) as *const i64);
        if (rsi as u64) <= (market_idx as u64) { return 0; }
        let rdx = *(clearinghouse_ptr.add(0xe0) as *const *mut u8);
        let rsi_2 = market_idx * 0x60;
        let entry_notional_3 = *(rdx.offset(rsi_2 as isize).add(0x40) as *const i64);
        let mut mkt_oracle_px_unit: [u64; 2] = *(rdx.offset(rsi_2 as isize).add(0x30) as *const [u64; 2]);
        let result_3 = *(rdx.offset(rsi_2 as isize).add(0x48) as *const i64);

        let ch = clearinghouse_ptr.add(0x60);
        let btree_node = *(ch.add(0x30) as *const *mut u8);
        if btree_node.is_null() { return 0; }

        let entry_notional = *(btree_node.offset(-0x30) as *const i64);
        let abs_notional_3 = *(btree_node.offset(-0x90) as *const i64);
        let abs_notional_2 = *(btree_node.offset(0x40) as *const i64);
        let rbx_2 = *(btree_node.offset(-0x28) as *const i64);

        let mut OPTION_UNIT_QTY_NONE_1: [u64; 2] = [0; 2];
        let mut var_198: [u64; 2] = [0; 2];
        let mut oracle_px_ptr: [u64; 2] = mkt_oracle_px_unit;
        let mut result = [0u64; 4];
        let leverage = compute_margin_requirement_by_mode(&mut result, &mut OPTION_UNIT_QTY_NONE_1, &mut var_198, 2, 0);

        let (account_value, abs_notional);
        if rbx_2 != 3 {
            let zmm2_2 = compute_margin_requirement_by_mode(&mut result, &mut var_198, &mut oracle_px_ptr, 1, leverage as i32);
            account_value = zmm2_2[0] as i64;
            abs_notional = abs_notional_2;
        } else {
            let zmm2_2 = compute_user_margin_and_shortfall(&mut OPTION_UNIT_QTY_NONE_1, clearinghouse_ptr, clearinghouse_ptr.add(0xd8), core::ptr::null_mut());
            account_value = zmm2_2[0] as i64;
            abs_notional = abs_notional_3;
        }

        let ratio1_margin_ratio: f64 = if abs_notional > 0 {
            (account_value as f64) / (abs_notional as f64)
        } else { 0.0 };

        let signed_notional_product_2 = result_3.wrapping_mul(entry_notional_3);
        let entry_notional_4 = if is_long == 0 { -entry_notional } else { entry_notional };
        let signed_notional_product = signed_notional_product_2 - entry_notional_4;
        let signed_notional_product_1 = if signed_notional_product > 0 { signed_notional_product } else { 0 };

        let ratio2: f64 = if entry_notional > 0 {
            (signed_notional_product_1 as f64) / (entry_notional as f64)
        } else { 0.0 };

        let r1 = ratio1_margin_ratio.max(1e-8);
        let r2 = ratio2.max(1e-8);
        let _ = (user_address, market_idx);
        (r1 * r2).to_bits() as i64
    }
}

