pub fn clearinghouse_adl_orchestrator(
    result: &mut BTreeMap24,
    ch: &Clearinghouse,
    adl_fill_ctx: *mut u8,
    oracle_asset_data: *const u8,
    adl_candidates: &mut BTreeMap24,
    arg6: *mut u8,
    arg7: *mut u8,
) -> &mut BTreeMap24 {
    let clearinghouse = ch;
    let counterparty_count = unsafe { *(clearinghouse as *const _ as *const u64).add(0xc) };
    let counterparty_array = unsafe { *(clearinghouse as *const _ as *const u64).add(0x42) };
    let mut total_shortfall_value: u128 = 0;
    let mut i: u64 = 0;
    while i < counterparty_count {
        let counterparty_addr = unsafe { *(counterparty_array as *const u64).add(i as usize * 4) };
        let user_shortfall = unsafe { *(counterparty_addr as *const u128) };
        total_shortfall_value = total_shortfall_value.wrapping_add(user_shortfall);
        let _ = (adl_fill_ctx, oracle_asset_data, adl_candidates as *const _, arg6, arg7);
        i = i.wrapping_add(1);
    }
    result.a = total_shortfall_value;
    result.b = i;
    result
}

