pub unsafe fn compute_position_liquidation_check(
    result: *mut u8,
    position: *mut u8,
    oracle_price: *mut u8,
    asset_info: *mut u8,
    clearinghouse: *mut Clearinghouse,
) {
    let mut work_buf: [u64; 3] = [0; 3];
    let mut oracle_price_optyqt: [u64; 3] = [0; 3];
    let mut margin_value_1: u64 = 0;

    if (oracle_price as usize) == 0 {
        let asset_info_extra: u64 = *(asset_info.add(0x10) as *const u64);
        oracle_price_optyqt[0] = *(asset_info as *const u64);
        oracle_price_optyqt[1] = *(asset_info.add(8) as *const u64);
        oracle_price_optyqt[2] = asset_info_extra;
        sub_555556b543a0(&mut work_buf, &oracle_price_optyqt);
        margin_value_1 = work_buf[2];
        *(result.add(0x10) as *mut u64) = margin_value_1;
        *(result as *mut u64) = work_buf[0];
        *(result.add(8) as *mut u64) = work_buf[1];
        return;
    }

    let mut none_result_tag: [u64; 2] = [2, 0];
    let mut none_result_margin: u64 = 0;
    let mut oracle_entries_ptr: *mut u8 = core::ptr::null_mut();
    let mut oracle_stride_offset: usize = 0;

    'none_path: {
        if *(position.add(0x80) as *const u64) <= (oracle_price as u64) {
            break 'none_path;
        }
        oracle_entries_ptr = *(position.add(0x78) as *const *mut u8);
        oracle_stride_offset = (oracle_price as usize) * 0xd0;
        if *(oracle_entries_ptr.add(oracle_stride_offset + 0x60) as *const u64) == 0 {
            break 'none_path;
        }
        let rsi: u64 = *((clearinghouse as *const u8).add(0x10) as *const u64);
        let rdi: u64 = **(oracle_entries_ptr.add(oracle_stride_offset + 0x58) as *const *const u64);
        if rdi >= rsi { return; }
        let rsi_1 = rdi.wrapping_mul(0xc8).wrapping_add(*((clearinghouse as *const u8).add(8) as *const u64));
        sub_555556b3f830(&mut work_buf, rsi_1 as *const u8);
        if work_buf[0] == 2 { break 'none_path; }

        oracle_price_optyqt = work_buf;
        if oracle_price_optyqt[0] == 2 { break 'none_path; }

        compute_per_position_liq_margin(
            &mut work_buf, asset_info, oracle_price,
            &oracle_price_optyqt, position.add(0x58),
        );

        let mut result_status_tag_1: u64 = work_buf[0];
        let mut margin_value: u64 = 0;
        let mut margin_value_2: u64 = 0;
        if result_status_tag_1 != 3 {
            margin_value = work_buf[2];
        }
        if margin_value == 0 { result_status_tag_1 = 2; }
        if margin_value >= 0x28f5c28f5c28f5c { result_status_tag_1 = 2; }
        let result_unit_1: u64 = work_buf[1];
        if margin_value < 0x28f5c28f5c28f5c { margin_value_2 = margin_value; }

        if (oracle_price as u64) != 1 {
            let asset_name_ptr: *const u32 =
                *(oracle_entries_ptr.add(oracle_stride_offset + 0x38) as *const *const u32);
            let temp0_1: u64 =
                *(oracle_entries_ptr.add(oracle_stride_offset + 0x40) as *const u64);
            let is_hype = temp0_1 == 4 && *asset_name_ptr == 0x45505948;
            let is_zxqj = temp0_1 >= 4 && *asset_name_ptr == 0x4a51585a;
            if !(is_hype || is_zxqj) {
                let result_status_tag: u64 = result_status_tag_1;
                let result_unit: u64 = result_unit_1;
                let mut margin_value_3: u64 = margin_value_2;
                let hype_floor_value: u64 = 0x2386f26fc10000;
                let work_buf_floor: [u64; 3] = [0, 0, hype_floor_value];
                let combined: [u64; 3] = [result_status_tag, result_unit, margin_value_3];
                let mut min_margin_ptr: *const [u64; 3] = &combined;
                if option_unit_qty_cmp(&combined, &work_buf_floor) == 1 {
                    min_margin_ptr = &work_buf_floor;
                }
                *(result as *mut u64) = (*min_margin_ptr)[0];
                *(result.add(8) as *mut u64) = (*min_margin_ptr)[1];
                margin_value_2 = (*min_margin_ptr)[2];
                *(result.add(0x10) as *mut u64) = margin_value_2;
                return;
            }
        }

        *(result as *mut u64) = result_status_tag_1;
        *(result.add(8) as *mut u64) = result_unit_1;
        *(result.add(0x10) as *mut u64) = margin_value_2;
        return;
    }

    *(result.add(0x10) as *mut u64) = none_result_margin;
    *(result as *mut u64) = none_result_tag[0];
    *(result.add(8) as *mut u64) = none_result_tag[1];
}
